const yasinText = `1. Yasın 2. Vel kur'anil hakiym 3. İnneke le minel murseliyn 4. Ala sıratım müstekıym 5. Tenziylel aziyzir rahıym 6. Li tünzira kavmem ma ünzira abaühüm fehüm ğafilun 7. Le kad hakkal kavlü ala ekserihim fehüm la yü'minun 8. İnna cealna fı a'nakıhim ağlalen fe hiye ilel ezkani fehüm mukmehun 9. Ve cealna mim beyni eydihim seddev ve min halfihim sedden fe ağşeynahüm fehüm la yübsırun 10. Ve sevaün aleyhim e enzertehüm em lem tünzirhüm la yü'minun 11. İnnema tünziru menittebeaz zikra ve haşiyer rahmane bil ğayb fe beşşirhü bi mağfirativ ve ecrin kerım 12. İnna nahnü nuhyil mevta ve nektübü ma kaddemu ve asarahüm ve külle şey'in ahsaynahü fı imamim mübiyn 13. Vadrib lehüm meselen ashabel karyeh iz caehel murselun 14. İz erselna ileyhimüsneyni fe kezzebuhüma fe azzezna bi salisin fe kalu inna ileyküm murselun 15. Kalu ma entüm illa beşerum mislüna ve ma enzeler rahmanü min şey'in in entüm illa tekzibun 16. Kalu rabbüna ya'lemü inna ileyküm le murselun 17. Ve ma aleyna illel belağul mübın 18. Kalu inna tetayyarna biküm leil lem tentehu le nercümenneküm ve le yemessenneküm minna azabün eliym 19. Kalu tairuküm meaküm ein zükkirtüm bel entüm kavmüm müsrifun 20. Ve cae min aksal medıneti racülüy yes'a kale ya kavmittebiul murseliyn 21. İttebiu mel la yes'elüküm ecrav vehüm mühtedun 22. Ve ma liye la a'büdüllezı fetaranı ve ileyhi türceun 23. E ettehızü min dunihı aliheten iy yüridnir rahmanü bi durril la tuğni annı şefaatühüm şey'ev ve la yünkızun 24. İnnı izel le fı dalalim mübın 25. İnnı amentü bi rabbiküm fesmeun 26. Kıyledhulil cenneh kale ya leyte kavmı ya'lemun 27. Bima ğafera lı rabbı ve cealenı minel mükramiyn 28. Ve ma enzelna ala kavmihı mim ba'dihı min cündim mines semai ve ma künna münziliyn 29. İn kanet illa sayhatev vahıdeten fe iza hüm hamidun 30. Ya hasraten alel ıbad ma yetiyhim mir rasulin illa kanu bihı yestehziun 31. Elem yerav kem ehlekna kablehüm minel kuruni ennehüm ileyhim la yarciun 32. Ve in küllül lemma cemiy'ul ledeyna muhdarun 33. Ve ayetül lehümül erdul meyteh ahyeynaha ve ahracna minha habben feminhü ye'külun 34. Ve cealna fiyha cennatim min nahıyliv ve a'nabiv ve feccerna fiyha minel uyun 35. Li ye'külu min semerihı ve ma amilethü eydiyhim efela yeşkürun 36. Sübhanellezı halekal ezvace külleha mimma tümbitül erdu ve min enfüsihim ve mimma la ya'lemun 37. Ve ayetül lehümül leyl neslehu minhün nehara fe iza hüm muslimun 38. Veş şemsü tecrı li müstekarril leha zalike takdiyrul aziyzil aliym 39. Vel kamera kaddernahü menazile hatta ade kel urcunil kadiym 40. Leşşemsü yembeğıy leha en tüdrikel kamera velel leylü sabikun nehar ve küllün fı felekiy yesbehun 41. Ve ayetül lehüm enna hamelna zürriyyetehüm fil fülkil meşhun 42. Ve halakna lehüm mim mislihı ma yarkebun 43. Ve in neşe' nuğrıkküm fela sariyha lehüm velahüm yünkazun 44. İlla rahmetem minna ve metaan ila hıyn 45. Ve iza kıyle lehümütteku ma beyne eydıküm ve ma halfeküm lealleküm türhamun 46. Ve ma te'tiyhim min ayetim min ayati rabbihim illa kanu anha mu'ridıyn 47. Ve iza kıyle lehüm enfiku mimma razekakümüllahü kalelleziyne keferu lilleziyne amenu e nut'ımü mel lev yeşaüllahü at'amehu in entüm illa fı dalalim mübın 48. Ve yekulune meta hazel va'dü in küntüm sadikıyn 49. Ma yenzurune illa sayhatev vahıdeten te'huzühüm vehüm yehıssımun 50. Fela yestetıy'une tevsıyetev ve la ila ehlihim yarciun 51. Ve nüfiha fis suri fe iza hüm minel ecdasi ila rabbihim yensilun 52. Kalu ya veylena mem beasena mim merkadina haza ma veader rahmanü ve sadekal murselun 53. İn kanet illa sayhatev vahıdeten feiza hüm cemiy'ul ledeyna muhdarun 54. Fel yevme la tuzlemü nefsün şey'ev vela tüczevne illa ma küntüm ta'melun 55. İnne ashabel cennetil yevme fı şüğulin fakihun 56. Hüm ve ezvacühüm fı zılalın alel eraiki müttekiun 57. Lehüm fiyha fakihetüv ve lehüm ma yeddeun 58. Selamün kavlem mir rabbir rahıym 59. Vemtazül yevme eyyühel mücrimun 60. Elem a'hed ileyküm ya benı ademe el la ta'büdüş şeytan innehu leküm adüvvüm mübiyn 61. Ve enı'büduni haza sıratum müstekıym 62. Ve lekad edalle minküm cibillen kesiyra efelem tekunu ta'kılun 63. Hazihı cehennemülletı küntüm tuadun 64. Islevhel yevme bima küntüm tekfürun 65. El yevme nahtimü ala efvahihim ve tükellimüna eydıhim ve teşhedü ercülühüm bima kanu yeksibun 66. Velev neşaü letamesna ala a'yünihim festebekus sırata fe enna yübsırun 67. Velev neşaü le mesahnahüm ala mekanetihim femestetau mudiyyev ve la yarciun 68. Ve men nüammirhü nünekkishü fil halk efela ya'kılun 69. Ve ma alemnahüş şı'ra ve ma yembeğıy leh in hüve illa zikruv ve kur'anüm mübiyn 70. Li yünzira men kane hayyave ve yehıkkal kavlü alel kafirın 71. E ve lem yerav enna halakna lehüm mimma amilet eydına en'amen fehüm leha malikun 72. Ve zellelnaha lehüm fe minha rakubühüm ve minha ye'külun 73. Ve lehüm fiyha menafiu ve meşarib efela yeşkürun 74. Vettehazu min dunillahi alihetel leallehüm yünsarun 75. La yestetıy'une nasrahüm vehüm lehüm cündüm muhdarun 76. Fela yahzünke kavlühüm inna na'lemü ma yüsirrune ve ma yu'linun 77. Evelem yeral insanü enna halaknahü min nutfetin fe iza hüve hasıymün mübın 78. Ve darabe lena meselev ve nesiye halkah kale mey yuhyil ızame ve hiye ramım 79. Kul yuhyıhellezı enşeeha evvele merrah ve hüve bi külli halkın alım 80. Ellezı ceale leküm mineş şeceril ahdari naran fe iza entüm minhü tukıdun 81. Eveleysellezı halekas semavati vel erda bi kadirin ala ey yahlüka mislehüm bela ve hüvel hallakul alım 82. İnnema emruhu iza erade şey'en ey yekule lehu kün fe yekun 83. Fe sübhanellezı bi yedihı melekutü külli şey'iv ve ileyhi türceun`;

const STORAGE_KEY_FONT_SIZE = 'yasin_font_size';

let currentFontSize = 14; // Default font size

export function loadYasin() {
    const contentEl = document.getElementById('yasin-content');
    const fontSizeInput = document.getElementById('yasin-font-size');
    
    if (!contentEl) {
        console.error('Yasin content elementi bulunamadı');
        return;
    }

    // Kaydedilmiş font boyutunu yükle
    chrome.storage.local.get(STORAGE_KEY_FONT_SIZE).then(saved => {
        if (saved[STORAGE_KEY_FONT_SIZE]) {
            currentFontSize = parseInt(saved[STORAGE_KEY_FONT_SIZE], 10) || 14;
        }
        
        if (fontSizeInput) {
            fontSizeInput.value = currentFontSize;
            
            // Font boyutu değişikliği dinle
            fontSizeInput.addEventListener('input', (e) => {
                const newSize = parseInt(e.target.value, 10);
                if (newSize >= 8 && newSize <= 24) {
                    currentFontSize = newSize;
                    applyFontSize();
                    // Değeri kaydet
                    chrome.storage.local.set({ [STORAGE_KEY_FONT_SIZE]: currentFontSize });
                }
            });
        }
        
        // İçeriği render et
        renderYasin();
    });
}

function renderYasin() {
    const contentEl = document.getElementById('yasin-content');
    if (!contentEl) return;

    // Metni parse et ve HTML'e çevir
    // Format: "1. Metin 2. Metin 3. Metin..."
    const parts = yasinText.split(/(\d+\.\s+)/);
    let html = '<div class="yasin-list">';
    
    // Ayetleri işle (her çift: numara + metin)
    for (let i = 1; i < parts.length; i += 2) {
        if (i + 1 < parts.length) {
            const num = parts[i].trim();
            const text = parts[i + 1].trim();
            if (text) {
                html += `<div class="yasin-item"><span class="yasin-num">${escapeHtml(num)}</span> <span class="yasin-text">${escapeHtml(text)}</span></div>`;
            }
        }
    }
    
    html += '</div>';
    contentEl.innerHTML = html;
    
    // Font boyutunu uygula
    applyFontSize();
}

function applyFontSize() {
    const contentEl = document.getElementById('yasin-content');
    if (!contentEl) return;
    
    const textElements = contentEl.querySelectorAll('.yasin-text');
    const numElements = contentEl.querySelectorAll('.yasin-num');
    
    textElements.forEach(el => {
        el.style.fontSize = currentFontSize + 'px';
    });
    
    numElements.forEach(el => {
        el.style.fontSize = currentFontSize + 'px';
    });
}

function escapeHtml(text) {
    if (!text) return '';
    return String(text)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#039;');
}
